Node removeValue(Node head, int val) {
    if (head != null && head.val == val) return head.next;
    Node prev = head;
    while (prev != null && prev.next != null) {
        if (prev.next.val == val) { prev.next = prev.next.next; return head; }
        prev = prev.next;
    }
    return head;
}
